      "tier": "D",
      "role": "Link Sharer",
      "action": "create a short URL via web form",
      "outcome": "short URL returned within 100 ms",
      "acceptance_criteria": [
        {
          "id": "AC-US001-001",
          "description": "Short URL returned within 100 ms",
          "measurable_condition": "POST /shorten returns 201 and the response body contains a slug within 100 ms"
        },
        {
          "id": "AC-US001-002",
          "description": "Slug is unique, 6 alphanumeric characters, and mapping is persisted",
          "measurable_condition": "POST /shorten with a valid long URL returns 201 and the response body contains a slug that is exactly 6 alphanumeric characters. Subsequent GET /url-mapping/{slug} returns the original URL within 1 second, and a SELECT query on URL_MAPPING_TABLE for that slug returns a single row, confirming uniqueness"
        },
        {
          "id": "AC-US001-003",
          "description": "Invalid URL input is rejected",
          "measurable_condition": "POST /shorten with a malformed URL returns HTTP 400 with JSON body containing error code 'INVALID_URL', and no new row is inserted into URL_MAPPING_TABLE"
        },
        {
          "id": "AC-US001-004",
          "description": "Original URL is stored encrypted at rest using AES-256",
          "measurable_condition": "After persisting a mapping, a SELECT query on URL_MAPPING_TABLE for that slug returns the original URL column encrypted with AES-256; attempting to decrypt with the system's encryption key yields the original URL, and the ciphertext value differs from the plaintext"
        },
        {
          "id": "AC-US001-005",
          "description": "Audit log entry is written for each successful shortening",
          "measurable_condition": "Immediately after a successful POST /shorten, a structured JSON log line is written to stdout containing fields actor_id, action='shorten', slug, and timestamp. The log aggregator ingests this line within 2 seconds, and the log entry is retrievable via the log aggregator API"
        }
      ],
      "traces_to": [
        "UJ-CREATE-SHORT-URL",
        "ENT-URL-MAPPING",
        "WF-CREATE-SHORT-URL"
      ],
      "decomposition_rationale": "Parent acceptance criteria are individually testable; no internal structure to decompose."
    }
  ],
  "surfaced_assumptions": [
    {
      "text": "Encryption key is available at runtime for AES-256 encryption of URL mappings",
      "category": "constraint",
      "citations": []
    }
  ]
}

